def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=np.float64)
    epsilon = 1e-9
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            if item > 0:
                priorities[i] = np.inf
            else:
                priorities[i] = 0
            continue
        ratio = item / capacity
        if abs(ratio) < epsilon:
            priorities[i] = 0
            continue
        if ratio < 0:
            val = 0
            for p in range(1, 5):
                term = ((-ratio) ** p) / (p ** 2)
                if p % 2 == 1:
                    val += term
                else:
                    val -= term
            priorities[i] = val * 7
            continue
        if ratio > 1:
            penalty = 0
            for k in range(1, 5):
                penalty += (ratio ** (2 * k + 1)) / (k * 3)
            base = ratio ** 4 - np.log1p(ratio)
            priorities[i] = base + penalty
            if capacity < item * 1.5:
                priorities[i] *= 2
            continue
        score = 0
        for j in range(1, 8):
            sign = 1 if (j % 3 == 0) else (-1 if j % 2 == 0 else 1)
            score += sign * (ratio ** j) / (j + 0.5)
        multiplier = 20 if ratio < 0.25 else 12 if ratio < 0.55 else 6 if ratio < 0.75 else 3
        priorities[i] = abs(score) * multiplier
        if 0.7 < ratio <= 1:
            extra = 0
            for m in range(1, 6):
                extra += (ratio ** (m * 1.1)) / (m + 0.7)
            priorities[i] += extra * 0.8
        if abs(capacity - item) < capacity * 0.05:
            priorities[i] *= 0.5
        if np.isclose(capacity, item, atol=capacity*0.01):
            priorities[i] *= 0.1
    return priorities
